1	// claim-office.ts
2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	export const KNOWN_ITEM_TYPES = new Set<string>([
16	  "sword",
17	  "amulet",
18	  "staff",
19	  "potion",
20	  "rune",
21	  "moonstone",
22	]);
23	
24	const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
27	const CURSED_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_YEARS_THRESHOLD = 2;
32	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
33	
34	function loyaltyDiscountFor(yearsInsured: number, baseTotal: number): number {
35	  return yearsInsured >= LOYALTY_YEARS_THRESHOLD ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
36	}
37	
38	function followUpDiscountFor(contractNumber: number, baseTotal: number): number {
39	  return contractNumber > 1 ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
40	}
41	
42	function withFirstInsurance(basePremium: number): number {
43	  return basePremium + basePremium * FIRST_INSURANCE_RATE;
44	}
45	
46	function premiumForTypeGroup(type: string, count: number): number {
47	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
48	    return withFirstInsurance(COMPONENT_BLOCK_BASE_PREMIUM);
49	  }
50	  return count * withFirstInsurance(BASE_PREMIUM_BY_ITEM_TYPE[type]);
51	}
52	
53	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
54	
55	function surchargeRateForItem(item: Item): number {
56	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
57	  const enchantmentRate =
58	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
59	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
60	      : 0;
61	  return cursedRate + enchantmentRate;
62	}
63	
64	function surchargeForItem(item: Item): number {
65	  return BASE_PREMIUM_BY_ITEM_TYPE[item.type] * surchargeRateForItem(item);
66	}
67	
68	const CLAIM_DEDUCTIBLE = 100;
69	const CAP_MULTIPLIER = 2;
70	const REDUCED_REIMBURSEMENT_RATE = 0.5;
71	const REDUCED_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
72	const MATERIALS_EXEMPT_FROM_REDUCED_REIMBURSEMENT = new Set<string>(["dragon"]);
73	
74	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
75	  sword: 1000,
76	  amulet: 600,
77	  staff: 800,
78	  potion: 400,
79	  rune: 250,
80	  moonstone: 250,
81	};
82	
83	type Damage = { type: string; amount: number };
84	
85	function insuranceCapFor(items: Item[]): number {
86	  const insuranceSum = items.reduce(
87	    (sum, item) => sum + INSURANCE_VALUE_BY_ITEM_TYPE[item.type],
88	    0,
89	  );
90	  return insuranceSum * CAP_MULTIPLIER;
91	}
92	
93	function isExemptFromReducedReimbursement(item: Item): boolean {
94	  return (
95	    COMPONENT_TYPES.has(item.type) ||
96	    MATERIALS_EXEMPT_FROM_REDUCED_REIMBURSEMENT.has(item.material ?? "")
97	  );
98	}
99	
100	function hasReducedReimbursement(item: Item): boolean {
101	  if (isExemptFromReducedReimbursement(item)) return false;
102	  return (item.enchantment ?? 0) >= REDUCED_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
103	}
104	
105	function reimbursementFor(damage: Damage, items: Item[]): number {
106	  const matchingItem = items.find((item) => item.type === damage.type);
107	  if (matchingItem && hasReducedReimbursement(matchingItem)) {
108	    return damage.amount * REDUCED_REIMBURSEMENT_RATE;
109	  }
110	  return damage.amount;
111	}
112	
113	function rawPayoutFor(damages: Damage[], items: Item[]): number {
114	  const reimbursementTotal = damages.reduce(
115	    (sum, d) => sum + reimbursementFor(d, items),
116	    0,
117	  );
118	  return reimbursementTotal - CLAIM_DEDUCTIBLE;
119	}
120	
121	function payoutAgainstCap(damages: Damage[], items: Item[], remainingCap: number): number {
122	  return Math.floor(Math.min(rawPayoutFor(damages, items), remainingCap));
123	}
124	
125	function handleClaim(scenario: any): { payout: number; remainingCap: number } {
126	  const damages: Damage[] = scenario.damages ?? [];
127	  const items: Item[] = scenario.items ?? [];
128	  const cap = insuranceCapFor(items);
129	  const payout = payoutAgainstCap(damages, items, cap);
130	  return { payout, remainingCap: cap - payout };
131	}
132	
133	function handleQuote(scenario: any): { premium: number } {
134	  const items: Item[] = scenario.items ?? [];
135	  const countsByType: Record<string, number> = {};
136	  let surchargesTotal = 0;
137	  let baseTotal = 0;
138	  for (const item of items) {
139	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
140	    surchargesTotal += surchargeForItem(item);
141	    baseTotal += BASE_PREMIUM_BY_ITEM_TYPE[item.type];
142	  }
143	  let itemsTotal = 0;
144	  for (const type of Object.keys(countsByType)) {
145	    itemsTotal += premiumForTypeGroup(type, countsByType[type]);
146	  }
147	  const yearsInsured = scenario.customer?.yearsInsured ?? 0;
148	  const contractNumber = scenario.customer?.contractNumber ?? 1;
149	  const loyaltyDiscount = loyaltyDiscountFor(yearsInsured, baseTotal);
150	  const followUpDiscount = followUpDiscountFor(contractNumber, baseTotal);
151	  return {
152	    premium: Math.ceil(itemsTotal + surchargesTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE),
153	  };
154	}
155	
156	function runSteps(scenario: any): unknown {
157	  const customer = scenario.customer;
158	  const policies: { items: Item[]; remainingCap: number }[] = [];
159	  const results: unknown[] = [];
160	  for (const step of scenario.steps) {
161	    if (step.op === "quote") {
162	      const items: Item[] = step.items ?? [];
163	      results.push(handleQuote({ customer, items }));
164	      policies.push({ items, remainingCap: insuranceCapFor(items) });
165	    } else if (step.op === "claim") {
166	      const policy = policies[step.policy];
167	      const damages: Damage[] = step.damages ?? [];
168	      const payout = payoutAgainstCap(damages, policy.items, policy.remainingCap);
169	      policy.remainingCap -= payout;
170	      results.push({ payout, remainingCap: policy.remainingCap });
171	    }
172	  }
173	  return { results };
174	}
175	
176	export function runScenario(scenario: any): unknown {
177	  if (scenario.steps) {
178	    return runSteps(scenario);
179	  }
180	  if (scenario.command === "claim") {
181	    return handleClaim(scenario);
182	  }
183	  return handleQuote(scenario);
184	}
